  1→(* ============================================================ *)
  2→(* PROG_SERVO: 서보 모터 제어                                    *)
  3→(* 역할: PC 명령 비트 → MC_xxx FB 실행 → 상태 비트 갱신          *)
  4→(* 축: _MC_AX[0] (인덱스 테이블 서보 1축)                        *)
  5→(* ============================================================ *)
  6→
  7→(* SafetyStop 시 서보 긴급 정지 *)
  8→IF g_SafetyStop THEN
  9→    g_bHomeExec   := FALSE;
 10→    g_bMoveExec   := FALSE;
 11→    g_bStopExec   := TRUE;
 12→    g_bResetExec  := FALSE;
 13→    g_bSetPosExec := FALSE;
 14→
 15→    g_FB_Stop(Axis := _MC_AX[0], Execute := g_bStopExec, Deceleration := 0);
 16→
 17→    %MW400 := 16#0002;
 18→    %MW401 := 0;
 19→    RETURN;
 20→END_IF;
 21→
 22→(* 1. PC 명령 비트 읽기 (MW300) *)
 23→bCmdHome    := %MW300.0;
 24→bCmdMove    := %MW300.1;
 25→bCmdJogCW   := %MW300.2;
 26→bCmdJogCCW  := %MW300.3;
 27→bCmdStop    := %MW300.4;
 28→bCmdReset   := %MW300.5;
 29→bCmdSetPos  := %MW300.6;
 30→bCmdServoOn := %MW300.7;
 31→
 32→(* 제어 부가 비트 (MW301) *)
 33→bMoveDir    := %MW301.0;
 34→bMoveRel    := %MW301.1;
 35→
 36→(* 2. 파라미터 읽기 (MW310~319, DINT = 2 WORD) *)
 37→dinTargetPos := WORD_TO_DINT(%MW310) + WORD_TO_DINT(%MW311) * 65536;
 38→dinTargetVel := WORD_TO_DINT(%MW312) + WORD_TO_DINT(%MW313) * 65536;
 39→dinJogVel    := WORD_TO_DINT(%MW314) + WORD_TO_DINT(%MW315) * 65536;
 40→dinAccel     := WORD_TO_DINT(%MW316) + WORD_TO_DINT(%MW317) * 65536;
 41→dinDecel     := WORD_TO_DINT(%MW318) + WORD_TO_DINT(%MW319) * 65536;
 42→
 43→(* 3. 엣지 트리거 검출 *)
 44→g_CMD_Home_RT(CLK := bCmdHome);
 45→g_CMD_Move_RT(CLK := bCmdMove);
 46→g_CMD_Stop_RT(CLK := bCmdStop);
 47→g_CMD_Reset_RT(CLK := bCmdReset);
 48→g_CMD_SetPos_RT(CLK := bCmdSetPos);
 49→
 50→(* 4. 명령 실행 플래그 세팅 *)
 51→IF g_CMD_Home_RT.Q THEN
 52→    g_bHomeExec := TRUE;
 53→END_IF;
 54→IF g_FB_Home.Done OR g_FB_Home.Error THEN
 55→    g_bHomeExec := FALSE;
 56→END_IF;
 57→
 58→IF g_CMD_Move_RT.Q THEN
 59→    g_bMoveExec := TRUE;
 60→END_IF;
 61→IF g_FB_MoveAbs.Done OR g_FB_MoveAbs.Error THEN
 62→    g_bMoveExec := FALSE;
 63→END_IF;
 64→
 65→IF g_CMD_Stop_RT.Q THEN
 66→    g_bStopExec := TRUE;
 67→END_IF;
 68→IF g_FB_Stop.Done OR g_FB_Stop.Error THEN
 69→    g_bStopExec := FALSE;
 70→END_IF;
 71→
 72→IF g_CMD_Reset_RT.Q THEN
 73→    g_bResetExec := TRUE;
 74→END_IF;
 75→IF g_FB_Reset.Done OR g_FB_Reset.Error THEN
 76→    g_bResetExec := FALSE;
 77→END_IF;
 78→
 79→IF g_CMD_SetPos_RT.Q THEN
 80→    g_bSetPosExec := TRUE;
 81→END_IF;
 82→IF g_FB_SetPos.Done OR g_FB_SetPos.Error THEN
 83→    g_bSetPosExec := FALSE;
 84→END_IF;
 85→
 86→(* 5. MC_xxx FB 호출 *)
 87→g_FB_Home(Axis := _MC_AX[0], Execute := g_bHomeExec);
 88→
 89→g_FB_MoveAbs(
 90→    Axis         := _MC_AX[0],
 91→    Execute      := g_bMoveExec,
 92→    Position     := DINT_TO_LREAL(dinTargetPos),
 93→    Velocity     := DINT_TO_LREAL(dinTargetVel),
 94→    Acceleration := DINT_TO_LREAL(dinAccel),
 95→    Deceleration := DINT_TO_LREAL(dinDecel),
 96→    Direction    := 0
 97→);
 98→
 99→g_FB_JogCW(
100→    Axis        := _MC_AX[0],
101→    JogForward  := bCmdJogCW,
102→    JogBackward := FALSE,
103→    Velocity    := DINT_TO_LREAL(dinJogVel),
104→    Acceleration := DINT_TO_LREAL(dinAccel),
105→    Deceleration := DINT_TO_LREAL(dinDecel)
106→);
107→
108→g_FB_JogCCW(
109→    Axis        := _MC_AX[0],
110→    JogForward  := FALSE,
111→    JogBackward := bCmdJogCCW,
112→    Velocity    := DINT_TO_LREAL(dinJogVel),
113→    Acceleration := DINT_TO_LREAL(dinAccel),
114→    Deceleration := DINT_TO_LREAL(dinDecel)
115→);
116→
117→g_FB_Stop(
118→    Axis         := _MC_AX[0],
119→    Execute      := g_bStopExec,
120→    Deceleration := DINT_TO_LREAL(dinDecel)
121→);
122→
123→g_FB_Reset(Axis := _MC_AX[0], Execute := g_bResetExec);
124→
125→g_FB_SetPos(
126→    Axis     := _MC_AX[0],
127→    Execute  := g_bSetPosExec,
128→    Position := DINT_TO_LREAL(dinTargetPos)
129→);
130→
131→(* 6. 서보 상태 비트 갱신 → MW400 *)
132→wStatus := 0;
133→
134→IF _MC_AX[0].IsMoving THEN
135→    wStatus := wStatus OR 16#0001;
136→END_IF;
137→IF _MC_AX[0].Error THEN
138→    wStatus := wStatus OR 16#0002;
139→END_IF;
140→IF _MC_AX[0].InPosition THEN
141→    wStatus := wStatus OR 16#0004;
142→END_IF;
143→IF _MC_AX[0].InPosition AND (NOT _MC_AX[0].IsMoving) THEN
144→    wStatus := wStatus OR 16#0008;
145→END_IF;
146→IF _MC_AX[0].IsHomed THEN
147→    wStatus := wStatus OR 16#0010;
148→END_IF;
149→IF _MC_AX[0].IsHoming THEN
150→    wStatus := wStatus OR 16#0020;
151→END_IF;
152→IF bCmdServoOn AND _00_IN01 THEN
153→    wStatus := wStatus OR 16#0040;
154→END_IF;
155→IF bCmdServoOn AND _MC_AX[0].IsHomed AND (NOT _MC_AX[0].Error) THEN
156→    wStatus := wStatus OR 16#0080;
157→END_IF;
158→
159→%MW400 := wStatus;
160→
161→(* 7. 명령 응답 비트 갱신 → MW401 *)
162→wResponse := 0;
163→
164→IF g_FB_Home.Done THEN
165→    wResponse := wResponse OR 16#0001;
166→END_IF;
167→IF g_FB_MoveAbs.Done THEN
168→    wResponse := wResponse OR 16#0002;
169→END_IF;
170→IF g_FB_Home.Error THEN
171→    wResponse := wResponse OR 16#0004;
172→END_IF;
173→IF g_FB_MoveAbs.Error THEN
174→    wResponse := wResponse OR 16#0008;
175→END_IF;
176→IF g_FB_Reset.Done THEN
177→    wResponse := wResponse OR 16#0010;
178→END_IF;
179→
180→%MW401 := wResponse;
181→
182→(* 8. 서보 상태값 갱신 → MW410~415 *)
183→%MW410 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualPosition) MOD 65536);
184→%MW411 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualPosition) / 65536);
185→%MW412 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualVelocity) MOD 65536);
186→%MW413 := DINT_TO_WORD(LREAL_TO_DINT(_MC_AX[0].ActualVelocity) / 65536);
187→%MW414 := _MC_AX[0].ErrorID;
188→%MW415 := LREAL_TO_WORD(_MC_AX[0].ActualPosition / 100.0);
189→
